var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 상업 지구, 본선 1경기 시작 <color=#ffd34c>10분 전</color>","JPN":"シャレード商業地区、本戦第1試合開始<color=#ffd34c>10分前</color>","ENG":"Charade Commercial District, <color=#ffd34c>10 minutes before</color> the start of the first elimination match","TWN":"查雷德商業區，第一回合決賽開始<color=#ffd34c>前10分鐘</color>","THA":"ย่านการค้าชาเรด<color=#ffd34c>10 นาทีก่อน</color>เริ่มการแข่งขันนัดแรก","VTN":"Khu thương mại Charade, <color=#ffd34c>10 phút trước khi</color> bắt đầu trận đấu loại trực tiếp đầu tiên","SCN":"查雷德商业区，距离淘汰赛第一场开始还有<color=#ffd34c>10分钟</color>","DEU":"Charades Geschäftsviertel, <color=#ffd34c>10 Minuten vor</color> dem ersten Spiel der Hauptrunde","FRA":"Quartier des affaires de Charade, <color=#ffd34c>10 minutes</color> avant le début du 1er match de la finale"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"……앞으로 10분 남았군.","JPN":"……あと10分だな。","ENG":"...10 minutes left.","TWN":"……只剩10分鐘。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"설마 샤레이드 쪽 구매 루트를 모두 봉쇄했다고 국외에서 함선을 조달할 줄이야.","JPN":"まさかシャレードの販売ルートを俺らが封鎖したからって、国外まで艦船を調達しに行くとは。","ENG":"Who'd have thought they would try to procure a ship from overseas after we blocked all normal purchasing routes.","TWN":"該不會因為我們把查雷德的採購管道都封鎖了，所以他們現在只能去國外借艦船吧？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"급하게 맺은 계약이라 지출이 크긴 하지만, 반군 출신의 현지 용병을 섭외할 수 있어서 다행이야.","JPN":"急な契約で出費がかさんだが、反乱軍出身の現地傭兵を雇うことができて助かったぜ。","ENG":"It cost us a pretty penny to make a last-minute deal, but I'm glad we could recruit those rebel mercenaries.","TWN":"因為時間很趕，所以簽約金有比較高，不過幸好可以請到叛軍出身的當地傭兵。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAX_CHARADE_NPC_MOB","text":{"KOREA":"그 녀석들 아마 경기용 모의탄 밖에 없을 텐데, 지금쯤이면 벌집이 되어 있겠군요.","JPN":"あいつら、たぶん試合用の模擬弾しか持ってないはずだし、今頃ハチの巣になってますね。","ENG":"Those canary chumps will only be carrying rubber bullets, so I bet they're all riddled with bullets by now.","TWN":"他們應該只有比賽用的漆彈，現在應該已經變成蜂窩了吧？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"흥, 녀석들이 죽든, 살든 그딴 건 우리 알 바 아니야.","JPN":"フン、奴らが死のうが生きようが、俺らの知ったことじゃねえ。","ENG":"Hmph. Doesn't matter to us if they're dead or alive.","TWN":"哼，不管他們是死是活都不關我們的事。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"어차피 시간은 우리 편이니까.","JPN":"どうせ時間は俺らの味方だ。","ENG":"Time is still on our side.","TWN":"反正時間上我們佔優勢。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"코핀 컴퍼니, 경기 시작 10분 전입니다.","JPN":"コフィンカンパニー、試合開始まであと10分です。","ENG":"Coffin Company, your match will start in 10 minutes.","TWN":"科芬公司，距離比賽開始只剩10分鐘。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"카나리아 스쿼드 측 선수들과 등록된 함선이 아직 도착하지 않은 것 같은데.","JPN":"カナリア・スクワッド側の選手と、登録された艦船がまだ到着していないようですが。","ENG":"Looks like Canary Squad's players and ship haven't arrived yet.","TWN":"但金絲雀小隊這邊的選手和登記的艦船似乎都還沒抵達。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시합이 불가능한 상황이라면, 지금이라도 출전 포기 선언을 하시겠습니까?","JPN":"試合が不可能な状況でしたら、今でも出戦放棄を宣言しますか？","ENG":"If you are unable to participate, it's best if you forfeit now.","TWN":"要是無法進行比賽，還是現在就先棄權呢？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"경기 시작 전에 출전 포기 선언을 하신다면, 리그 규정 상 정상 탈락처리가 됩니다.","JPN":"試合開始前に出戦放棄を宣言されますと、リーグの規定上、正式な脱落処理となります。","ENG":"If you do forfeit before the match starts, you will be disqualified according to the league regulations.","TWN":"現在棄權的話，根據聯賽規定會視為正常淘汰。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"경기가 시작하기 전까지 우리 팀이 도착하지 못하면 어떻게 되는데?","JPN":"試合開始前までに私たちのチームが到着できなかったらどうなるの？","ENG":"What happens if our team doesn't arrive on time?","TWN":"那如果我們的選手來不及抵達的話會怎麼樣？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"사전 조율 없는 일방적인 경기 취소는 향후 3년간 리그 출전 정지 처분을 받습니다.","JPN":"事前調整のない一方的な試合のキャンセルは、今後3年間リーグ出戦停止処分となります。","ENG":"Canceling the match without prior agreement will result in a three-year suspension.","TWN":"在未事先告知的情況下取消比賽，將懲罰該隊禁賽三年。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐? 우리 쪽 잘못이 아니라고 해도?","JPN":"は？　私たちのミスじゃなくても？","ENG":"What?! Even if it's not our fault?","TWN":"什麼？就算錯不在我們？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"네? 무슨 말씀이신지 이해가 잘 안 되는데요?","JPN":"はい？　何をおっしゃっているのか、よく理解できませんが。","ENG":"Pardon? I don't understand what you mean by that.","TWN":"什麼？我不明白你的意思？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"다 알면서 모른 척 할 셈이야? 지금……!","JPN":"全部知ってるくせに、知らないふりするつもり？　今……！","ENG":"Oh, so you're going to pretend you don't know? Are you–","TWN":"你明明就知道還裝傻？可惡……！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};